import React, { Component } from 'react'
import Skill from '../components/Skill'
import {COLORS} from '../components/Colors'

export default class SkillContainer extends Component {
    state = {
        itemsHtml: []
    }

    componentDidMount() {
        let arr = []
        for(let i = 0; i < this.props.names.length; i++) {
            arr.push(<Skill img={this.props.imgs[i]} name={this.props.names[i]} />)
        }
        this.setState({itemsHtml:arr})
    }

    render() {
        return (
            <div className="block my-5 bg-white rounded p-8 shadow-2xl">
                <h2 className="text-4xl uppercase w-full border-b pb-3" style={{color: COLORS.primary, borderColor: COLORS.primary}} >{this.props.title}</h2>
                <div>
                    {this.state.itemsHtml}
                </div>
            </div>
        )
    }
}
