import React, { Component } from 'react'
import { COLORS } from './Colors'

export default class School extends Component {
    state = {
        types: []
    }

    componentDidMount() {
        let typesHtml = []
        for(const i of this.props.type) {
            typesHtml.push(<li>{i}</li>)
        }
        this.setState({ types: typesHtml })
    }

    render() {
        return (
            <div className="p-10 my-5 md:my-0 bg-white md:w-2/5 md:mx-5 rounded shadow-2xl">
                <h2 className="uppercase text-2xl hover:underline" style={{color: COLORS.primary}} ><a href={this.props.url} target="_blank">{this.props.school}</a></h2>
                <span className="text-gray-700 block mb-3" >{this.props.year}</span>
                <ul className="list-disc list-inside">
                    {this.state.types}
                </ul>
            </div>
        )
    }
}
