import React, { Component } from 'react'
import {COLORS} from './Colors'

export default class ContactItem extends Component {
    render() {
        return (
            <a href={this.props.url} className="block my-5 bg-white rounded p-5 shadow-2xl">
                <div style={{ background: COLORS.primary }} className="inline-block align-middle text-center rounded-full w-16 h-16">
                    <i className={this.props.icon + " text-3xl text-white block transform -translate-y-2/4"} style={{ marginTop:"50%" }}></i>
                </div>
                <span className="hover:underline inline-block align-middle text-xl ml-5" style={{color: COLORS.primary}}>{this.props.text}</span>
            </a>
        )
    }
}
